import gmpy2
import libnum

#如果题目没给e，根据低加密指数广播攻击的特性猜e=3、10、17等
e = 65537

n0 = int('',5)
c0 = int('',5)
n1 = int('',5)
c1 = int('',5)

n=[n0,n1]
c=[c0,c1]

for i in range(len(n)):
    for j in range(len(n)):
        if(i!=j):
            if(gmpy2.gcd(n[i],n[j])!=1):   #对不同的n进行 欧几里得算法，以求出最大公约数(p)
                print(i,j)                 #输出对应的n的序号
                p = gmpy2.gcd(n[i],n[j])
                print("p = ",p)
                q = n[i] // p
                print("q = ",q)
                d = gmpy2.invert(e , (p-1)*(q-1))
                print("d = ",d)
                m = pow(c[i],d,n[i])
                print("m = ",m)

print(libnum.n2s(int(m)))